export const userLayoutStyles = {
    wrapper: {
        display: 'flex', flexDirection: 'column',
        minHeight: '100vh', fontFamily: 'sans-serif'
    },

    // Header
    header: {
        display: 'flex', alignItems: 'center',
        justifyContent: 'space-between',
        padding: '0 32px', height: 60,
        background: '#fff', borderBottom: '1px solid #e5e7eb',
        position: 'sticky', top: 0, zIndex: 100
    },
    logo: { fontWeight: 700, fontSize: 18, color: '#dc2626' },
    nav: { display: 'flex', gap: 8 },

    // Avatar
    avatarWrap: { position: 'relative' },
    avatar: {
        width: 38, height: 38, borderRadius: '50%',
        background: '#dc2626', color: '#fff',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontWeight: 700, fontSize: 15, cursor: 'pointer',
        border: '2px solid #e5e7eb', userSelect: 'none'
    },

    // Dropdown
    dropdown: {
        position: 'absolute', top: 48, right: 0,
        background: '#fff', borderRadius: 8, width: 220,
        boxShadow: '0 4px 20px rgba(0,0,0,0.12)',
        border: '1px solid #e5e7eb', overflow: 'hidden', zIndex: 200
    },
    dropHeader: {
        padding: '14px 16px', borderBottom: '1px solid #e5e7eb',
        background: '#f9fafb'
    },
    dropName: { fontWeight: 700, fontSize: 14, color: '#111' },
    dropEmail: { fontSize: 12, color: '#6b7280', marginTop: 2 },
    dropItem: {
        display: 'flex', alignItems: 'center', gap: 10,
        padding: '11px 16px', fontSize: 14, color: '#374151',
        textDecoration: 'none', cursor: 'pointer',
        background: 'none', border: 'none', width: '100%',
        textAlign: 'left'
    },
    dropDivider: { height: 1, background: '#e5e7eb', margin: 0 },
    dropLogout: {
        display: 'flex', alignItems: 'center', gap: 10,
        padding: '11px 16px', fontSize: 14, color: '#dc2626',
        background: 'none', border: 'none', width: '100%',
        textAlign: 'left', cursor: 'pointer'
    },

btnLogin: {
  padding: '7px 18px', background: 'transparent',
  border: '1px solid #dc2626', color: '#dc2626',
  borderRadius: 6, fontWeight: 600, fontSize: 14, cursor: 'pointer',
},
btnRegister: {
  padding: '7px 18px', background: '#dc2626',
  border: 'none', color: '#fff',
  borderRadius: 6, fontWeight: 600, fontSize: 14, cursor: 'pointer',
},
    // Main content
    main: { flex: 1, padding: 32, background: '#f9fafb' },
};
